(function () {
  if (typeof window === 'undefined') return;
  if (!window.QUIZ_DATA) window.QUIZ_DATA = {};

  const extra8 = {
    "applicazioni-web": [
      { id:51, type:"mc", topic:"Architettura", text:"Cosa rappresenta il pattern architetturale 'Single Page Application' (SPA)?", options:["Un'applicazione web in cui UNA SOLA pagina HTML viene caricata inizialmente, e il contenuto viene aggiornato DINAMICAMENTE tramite JavaScript (manipolando il DOM e comunicando con il server via API/AJAX) senza ricaricare l'intera pagina ad ogni interazione", "Un sito web composto da una sola pagina statica senza alcuna interattività", "Un'applicazione che funziona solo su dispositivi mobili", "Un sinonimo di sito web con un solo file CSS"], correct:0, explanation:"In una SPA (es. realizzata con React, Vue, Angular, ma anche con JavaScript 'vanilla'), la navigazione tra 'sezioni' avviene aggiornando il DOM via JavaScript e recuperando dati tramite chiamate API (fetch/AJAX), senza richiedere al server una nuova pagina HTML completa ad ogni click; vantaggi: esperienza utente più fluida (no 'flash' di ricaricamento); svantaggi: maggiore complessità lato client, SEO più complessa, necessità di gestire il 'routing' client-side." },
      { id:52, type:"mc", topic:"HTTP", text:"Qual è la differenza principale tra i metodi HTTP PUT e PATCH in un'API REST?", options:["PUT è usato tipicamente per SOSTITUIRE COMPLETAMENTE una risorsa esistente (inviando TUTTI i suoi campi); PATCH è usato per MODIFICARE PARZIALMENTE una risorsa (inviando solo i campi da cambiare)", "Sono sinonimi esatti, intercambiabili", "PUT è usato solo per leggere dati, PATCH per scriverli", "PATCH funziona solo con dati XML, PUT solo con JSON"], correct:0, explanation:"Per convenzione REST: PUT /utenti/5 con body {nome:'Mario', email:'m@x.com', eta:30} SOSTITUISCE l'intera risorsa con id 5 (se un campo non è incluso, potrebbe essere considerato 'rimosso' o impostato a default); PATCH /utenti/5 con body {eta:31} modifica SOLO il campo 'eta', lasciando gli altri campi inalterati - utile per aggiornamenti parziali senza dover rinviare l'intero oggetto." },
      { id:53, type:"open", topic:"Sicurezza", text:"Spiega cosa significa 'sanitizzazione' dell'input in un'applicazione web e in cosa differisce dalla 'validazione'.", modelAnswer:"VALIDAZIONE: verifica che un dato INSERITO dall'utente RISPETTI determinati CRITERI (formato, range, lunghezza, tipo) PRIMA di accettarlo - es. verificare che un'email contenga '@' e un dominio valido, che un'età sia un numero tra 0 e 120, che un campo obbligatorio non sia vuoto; se la validazione FALLISCE, il dato viene RESPINTO (con un messaggio di errore all'utente). SANITIZZAZIONE: TRASFORMA il dato per renderlo SICURO da usare in un determinato CONTESTO, anche se il dato 'passa' la validazione - es. 'htmlspecialchars()' trasforma '<' in '&lt;' per renderlo sicuro da inserire in HTML (prevenendo XSS), 'addslashes()' (o meglio, prepared statement) per renderlo sicuro in query SQL (prevenendo SQL injection). DIFFERENZA CHIAVE: la validazione decide se ACCETTARE o RESPINGERE un input in base alla sua CORRETTEZZA SEMANTICA (è un'email valida? un numero nel range giusto?); la sanitizzazione TRASFORMA il dato (anche valido) per neutralizzare caratteri PERICOLOSI nel CONTESTO in cui verrà USATO (HTML, SQL, shell di sistema, URL, ecc.) - lo stesso dato potrebbe richiedere sanitizzazioni DIVERSE in contesti diversi (es. un nome utente che contiene '<' è valido come stringa, ma deve essere sanitizzato (escaped) PRIMA di essere mostrato in HTML).", keywords:["validazione: verifica che l'input rispetti criteri di formato/range/tipo, accettando o respingendo il dato", "sanitizzazione: trasforma il dato per renderlo sicuro nel contesto di utilizzo (HTML, SQL, ecc.)", "esempio validazione: controllo formato email o range numerico", "esempio sanitizzazione: htmlspecialchars() per output HTML, prepared statement per SQL", "lo stesso dato puo' richiedere sanitizzazioni diverse in contesti diversi"] },
      { id:54, type:"mc", topic:"Cache", text:"Cosa fa l'header HTTP 'Cache-Control: no-store' inviato da un server in risposta a una richiesta?", options:["Istruisce il browser (e qualsiasi cache intermedia) a NON memorizzare ALCUNA copia della risposta, richiedendo SEMPRE una nuova richiesta al server per ottenere il contenuto - utile per dati sensibili o che cambiano frequentemente", "Istruisce il browser a memorizzare la risposta per sempre, senza mai richiederla nuovamente", "È un header obsoleto, sostituito da Content-Type", "Funziona solo per immagini, non per dati JSON"], correct:0, explanation:"'Cache-Control' controlla il comportamento della cache (browser, proxy, CDN); 'no-store' è la direttiva più restrittiva: vieta QUALSIASI memorizzazione della risposta, neanche temporanea - appropriato per risposte contenenti dati SENSIBILI (es. saldo conto bancario, dati personali) che NON devono persistere in cache; altre direttive come 'max-age=3600' permettono cache per un periodo specifico, utile per risorse statiche (CSS, immagini) che cambiano raramente." },
      { id:55, type:"mc", topic:"WebSocket", text:"In cosa differisce una connessione WebSocket da una tradizionale richiesta HTTP request/response?", options:["WebSocket stabilisce una connessione PERSISTENTE e BIDIREZIONALE tra client e server, permettendo a ENTRAMBI di inviare messaggi in QUALSIASI momento senza dover iniziare una nuova richiesta per ogni scambio - utile per chat in tempo reale, notifiche live, giochi multiplayer", "WebSocket è solo un nome alternativo per AJAX", "WebSocket funziona solo per il trasferimento di file", "Una connessione WebSocket si chiude automaticamente dopo ogni messaggio, come HTTP"], correct:0, explanation:"HTTP tradizionale è un protocollo 'request-response': il client INIZIA sempre lo scambio, e il server può solo RISPONDERE; per ottenere aggiornamenti 'in tempo reale' con HTTP si dovrebbe fare polling ripetuto. WebSocket (avviato con un handshake HTTP iniziale, poi 'upgradato' a connessione persistente) permette al SERVER di inviare messaggi al client SENZA che il client li richieda esplicitamente, e viceversa, su un'UNICA connessione mantenuta APERTA - ideale per chat, notifiche push, dashboard in tempo reale, giochi online." },
      { id:56, type:"mc", topic:"Performance web", text:"Cosa fa la tecnica 'lazy loading' applicata alle immagini in una pagina web (es. attributo loading='lazy' su <img>)?", options:["Ritarda il CARICAMENTO di un'immagine fino a quando NON sta per entrare nella parte VISIBILE della finestra (viewport) durante lo scroll, riducendo il tempo di caricamento iniziale della pagina e il consumo di banda per immagini che l'utente potrebbe non visualizzare mai", "Carica tutte le immagini in qualità ridotta permanentemente", "Impedisce completamente il caricamento delle immagini", "Carica le immagini in ordine alfabetico per nome file"], correct:0, explanation:"Su pagine con MOLTE immagini (es. un catalogo prodotti), caricare TUTTE le immagini immediatamente al caricamento della pagina (anche quelle 'fuori schermo', visibili solo dopo molto scroll) spreca banda e ritarda il caricamento iniziale; 'loading=\"lazy\"' istruisce il browser a CARICARE l'immagine SOLO quando l'utente sta per VEDERLA (si avvicina con lo scroll), migliorando il tempo di caricamento PERCEPITO e riducendo il traffico per contenuti non visualizzati." },
      { id:57, type:"mc", topic:"Form e upload", text:"Quale attributo deve avere un tag <form> HTML per permettere l'upload di FILE tramite un campo <input type='file'>?", options:["enctype='multipart/form-data'", "method='GET'", "accept-charset='UTF-8'", "target='_blank'"], correct:0, explanation:"Per default, i form HTML codificano i dati come 'application/x-www-form-urlencoded' (adatto per testo, non per dati binari come i file); 'enctype=\"multipart/form-data\"' cambia la codifica per supportare l'INVIO DI FILE BINARI insieme ad altri campi del form - senza questo attributo, il file selezionato dall'utente NON verrebbe trasmesso correttamente al server." },
      { id:58, type:"mc", topic:"Sicurezza", text:"Cosa rappresenta un attacco di tipo 'Clickjacking'?", options:["Una tecnica in cui un sito malevolo SOVRAPPONE (tramite iframe TRASPARENTE) la pagina di un sito legittimo sopra contenuti ingannevoli, inducendo l'utente a cliccare INVOLONTARIAMENTE su elementi della pagina legittima (es. un pulsante 'autorizza pagamento') pensando di interagire con altro", "Un attacco che ruba le password tramite keylogger", "Un attacco che sovraccarica il server con troppe richieste", "Un sinonimo di SQL injection"], correct:0, explanation:"Nel clickjacking, l'attaccante crea una pagina con un IFRAME TRASPARENTE che carica un sito legittimo (es. la pagina 'elimina account' o 'autorizza transazione' di un servizio dove l'utente è loggato), posizionato sopra elementi 'visibili' e attraenti della pagina malevola; l'utente, cliccando su ciò che VEDE, in realtà clicca sul pulsante NASCOSTO del sito legittimo. DIFESA: l'header 'X-Frame-Options: DENY' (o 'Content-Security-Policy: frame-ancestors none') impedisce che la pagina venga caricata dentro un iframe da altri siti." },
      { id:59, type:"mc", topic:"Architettura", text:"Cosa rappresenta un 'load balancer' in un'architettura web ad alto traffico?", options:["Un componente che distribuisce le richieste HTTP entranti tra MULTIPLI server applicativi (backend), evitando che un singolo server sia sovraccaricato, e migliorando disponibilità/scalabilità", "Un componente che comprime le immagini automaticamente", "Un sinonimo di database", "Un tipo di cache solo per file CSS/JS"], correct:0, explanation:"Quando un singolo server non è più sufficiente a gestire il traffico (o per garantire disponibilità anche se un server si guasta), si replicano le istanze dell'applicazione su PIÙ SERVER; un load balancer (es. Nginx, HAProxy, o servizi cloud come AWS ELB) si pone DAVANTI a questi server e DISTRIBUISCE le richieste in arrivo tra essi secondo varie strategie (round-robin, basato sul carico, ecc.), e può anche rilevare server 'non sani' ed escluderli temporaneamente dal traffico." },
      { id:60, type:"mc", topic:"Autenticazione", text:"Cosa rappresenta il flusso 'OAuth 2.0' in termini generali, es. 'Accedi con Google'?", options:["Un protocollo che permette a un'applicazione (es. un sito web) di ottenere ACCESSO LIMITATO alle informazioni di un utente su un servizio terzo (es. Google), tramite un TOKEN, SENZA che l'utente debba condividere la propria PASSWORD del servizio terzo con l'applicazione", "Un protocollo per criptare le password nel database", "Un sinonimo di HTTPS", "Un linguaggio di programmazione per autenticazione"], correct:0, explanation:"Con OAuth 2.0, l'utente viene REINDIRIZZATO al provider (es. Google), dove ACCONSENTE che l'applicazione richiedente acceda a CERTE informazioni (es. nome, email) o azioni (es. pubblicare su un calendario) per suo conto; il provider rilascia un TOKEN DI ACCESSO all'applicazione, che lo usa per le richieste API SENZA che l'applicazione venga MAI a conoscenza della password dell'utente sul servizio Google - l'utente può anche REVOCARE l'accesso in qualsiasi momento dalle impostazioni del provider." },
      { id:61, type:"mc", topic:"Versioning API", text:"Perché è importante il 'versioning' (versionamento) di un'API REST, es. /api/v1/utenti vs /api/v2/utenti?", options:["Permette di introdurre MODIFICHE INCOMPATIBILI (breaking changes) all'API in una NUOVA versione, mantenendo FUNZIONANTE la versione PRECEDENTE per i client (es. app mobile già pubblicate) che non sono ancora stati aggiornati per usare la nuova versione", "È richiesto dal protocollo HTTP, senza versioning l'API non funziona", "Serve solo per scopi estetici dell'URL", "Il versioning rallenta sempre l'API"], correct:0, explanation:"Se un'API cambia il FORMATO di una risposta (es. rinomina un campo, cambia la struttura JSON), i client che si aspettano il VECCHIO formato SI ROMPEREBBERO; mantenendo '/api/v1/...' invariato e introducendo '/api/v2/...' con le modifiche, i client esistenti continuano a funzionare con v1 mentre i NUOVI client (o quelli aggiornati) possono adottare v2 - permettendo una TRANSIZIONE GRADUALE, dopo la quale v1 può essere eventualmente DEPRECATA e rimossa con preavviso." },
      { id:62, type:"open", topic:"Performance", text:"Spiega cosa significa 'N+1 query problem' in un'applicazione web che usa un database relazionale, con un esempio concreto, e come si potrebbe risolvere.", modelAnswer:"Il problema N+1 si verifica quando, per visualizzare una LISTA di N elementi PADRE, e per OGNUNO di essi si esegue UNA QUERY SEPARATA per recuperare dati CORRELATI (figli), risultando in 1 query per la lista + N query aggiuntive (una per elemento) = N+1 query totali. ESEMPIO CONCRETO: una pagina mostra una lista di 20 Articoli, e per CIASCUN articolo deve mostrare il nome dell'AUTORE. Un'implementazione 'naive' farebbe: (1) 'SELECT * FROM Articoli LIMIT 20' (1 query) per ottenere gli articoli; (2) per OGNUNO dei 20 articoli, 'SELECT nome FROM Autori WHERE id = ?' (20 query separate, una per articolo) - totale 21 query, anche se concettualmente serve 'solo' recuperare articoli E autori. PROBLEMA: ogni query ha un OVERHEAD (latenza di rete verso il database, parsing, ecc.); con 20 query aggiuntive 'piccole' invece di 1 query 'grande', il TEMPO TOTALE può essere significativamente maggiore, specialmente con database remoti. SOLUZIONE: usare un JOIN per recuperare articoli E autori in UNA SOLA query: 'SELECT a.*, au.nome AS nome_autore FROM Articoli a JOIN Autori au ON a.id_autore = au.id LIMIT 20' - UNA query restituisce TUTTI i dati necessari, eliminando le 20 query aggiuntive. In alternativa (se il JOIN producesse troppe colonne duplicate), si può fare una SECONDA query con 'WHERE id IN (lista_di_id_autori)' per recuperare TUTTI gli autori necessari in UNA query, poi 'unire' i dati in memoria nell'applicazione (2 query totali invece di 21).", keywords:["N+1: 1 query per la lista + N query separate (una per ogni elemento) per dati correlati", "esempio: lista di articoli, una query separata per l'autore di ciascun articolo", "problema: overhead di latenza per ogni query aggiuntiva, specialmente con database remoti", "soluzione: JOIN per ottenere tutto in una query, oppure una seconda query con WHERE id IN (...)"] },
      { id:63, type:"mc", topic:"Headers HTTP", text:"Cosa indica l'header di richiesta HTTP 'Accept: application/json' inviato dal client al server?", options:["Il client indica al server quale FORMATO preferisce per la risposta (in questo caso JSON); il server PUÒ (ma non è obbligato) restituire i dati in quel formato, scegliendo tra i formati che supporta", "Il client sta inviando dati JSON nel body della richiesta", "L'header Accept è obbligatorio per tutte le richieste HTTP", "Forza il server a rispondere sempre con status 200"], correct:0, explanation:"L'header 'Accept' è parte del meccanismo di 'content negotiation': il CLIENT comunica i formati di risposta che è in grado di INTERPRETARE/preferisce (es. 'application/json', 'text/html', 'application/xml'), e il server (se supporta più formati per la stessa risorsa) può scegliere il formato da restituire in base a questo header, indicandolo poi nella risposta con 'Content-Type'. Diverso da 'Content-Type' nella RICHIESTA, che descrive il formato dei dati INVIATI dal client (es. nel body di una POST)." },
      { id:64, type:"mc", topic:"Sicurezza", text:"Cosa rappresenta il principio 'fail securely' (fallire in modo sicuro) applicato alla gestione degli errori in un'applicazione web?", options:["In caso di ERRORE (es. eccezione non gestita, errore del database), l'applicazione deve DEFAULT verso lo stato PIÙ RESTRITTIVO (es. NEGARE l'accesso, non mostrare dati), evitando che un errore imprevisto causi ACCIDENTALMENTE un comportamento PIÙ PERMISSIVO (es. bypass di un controllo di autorizzazione)", "Gli errori non devono mai essere registrati nei log", "L'applicazione deve sempre mostrare il messaggio di errore completo (stack trace) all'utente", "Fail securely significa che l'applicazione non deve mai gestire errori"], correct:0, explanation:"Esempio CONCRETO: 'if (verificaPermesso($utente)) { mostraDatiSensibili(); } else { negaAccesso(); }' - se 'verificaPermesso()' lancia un'eccezione IMPREVISTA (es. database non raggiungibile), e questa NON viene gestita correttamente, il flusso potrebbe 'saltare' direttamente a 'mostraDatiSensibili()' se il codice è scritto male (es. un blocco try senza else esplicito che lascia passare per default); il principio 'fail securely' richiede di progettare il codice in modo che QUALSIASI ECCEZIONE/ERRORE porti SEMPRE allo stato di accesso NEGATO per default, non concesso." },
      { id:65, type:"mc", topic:"Database connection", text:"Cosa rappresenta un 'connection pool' (pool di connessioni) verso il database in un'applicazione web?", options:["Un insieme di connessioni al database GIÀ APERTE e mantenute pronte per essere RIUTILIZZATE da richieste successive, evitando il costo (relativamente alto) di APRIRE una NUOVA connessione TCP/autenticazione per ogni singola richiesta", "Un pool è un tipo di query SQL per raggruppare risultati", "Una funzionalità che limita il numero massimo di righe in una tabella", "Un sinonimo di backup del database"], correct:0, explanation:"Aprire una connessione al database (handshake TCP, autenticazione) ha un COSTO non trascurabile in termini di TEMPO; in un'applicazione che gestisce MOLTE richieste, aprire/chiudere una connessione per OGNI richiesta sarebbe inefficiente; un connection pool mantiene un certo numero di connessioni APERTE e le 'presta' alle richieste che ne hanno bisogno, RESTITUENDOLE al pool (non chiudendole) al termine - riducendo drasticamente l'overhead di connessione e migliorando il throughput complessivo dell'applicazione." },
      { id:66, type:"open", topic:"Sicurezza", text:"Spiega cosa significa 'Content Security Policy' (CSP) come meccanismo di difesa, e come può mitigare l'impatto di un attacco XSS anche se l'attaccante riesce a iniettare codice HTML/JavaScript.", modelAnswer:"CSP è un meccanismo basato su un HEADER HTTP ('Content-Security-Policy') con cui il server DICHIARA al browser quali ORIGINI (domini) sono AUTORIZZATE a fornire CONTENUTI di vari tipi (script, stili, immagini, ecc.) per quella pagina, e quali comportamenti sono PERMESSI. ESEMPIO: 'Content-Security-Policy: script-src \\'self\\' https://cdn.esempio.com' indica che SCRIPT JAVASCRIPT possono essere caricati SOLO dal proprio dominio ('self') o da 'https://cdn.esempio.com' - QUALSIASI altro script (incluso script INLINE, a meno di direttive specifiche, o script da domini non whitelistati) viene BLOCCATO dal BROWSER, anche se presente nell'HTML della pagina. MITIGAZIONE XSS: se un attaccante riesce a INIETTARE '<script>codiceMalevolo()</script>' tramite una vulnerabilità XSS (es. un campo non sanitizzato), e la pagina ha una CSP che NON permette script inline ('script-src \\'self\\'' senza 'unsafe-inline'), il BROWSER STESSO si rifiuterà di ESEGUIRE quello script iniettato, anche se è presente nel DOM - questo NON CORREGGE la vulnerabilità XSS sottostante (l'input non sanitizzato rimane un problema), ma fornisce un LIVELLO DI DIFESA AGGIUNTIVO (defense in depth) che PUÒ impedire l'esecuzione effettiva del payload malevolo, riducendo il DANNO anche se la prima linea di difesa (sanitizzazione) fallisce.", keywords:["CSP e' un header HTTP che dichiara quali origini possono fornire script/stili/immagini per la pagina", "esempio: script-src 'self' permette script solo dal proprio dominio, bloccando script inline non autorizzati", "se un attaccante inietta <script> via XSS, il browser si rifiuta di eseguirlo se non conforme alla CSP", "CSP non corregge la vulnerabilita' XSS sottostante ma fornisce defense in depth"] },
      { id:67, type:"mc", topic:"Compressione", text:"Cosa fa la compressione GZIP applicata alle risposte HTTP (header 'Content-Encoding: gzip')?", options:["Riduce la DIMENSIONE dei dati trasferiti dal server al client (specialmente per contenuti testuali come HTML/CSS/JS/JSON, che si comprimono molto bene), diminuendo i tempi di trasferimento; il browser DECOMPRIME automaticamente la risposta", "Cripta i dati per sicurezza", "Aumenta la dimensione dei file per backup", "Funziona solo per immagini"], correct:0, explanation:"GZIP è un algoritmo di compressione 'lossless' (senza perdita); il server comprime la risposta PRIMA di inviarla (se il client indica supporto con 'Accept-Encoding: gzip'), riducendo significativamente la BANDA necessaria per contenuti testuali (spesso 60-80% di riduzione per HTML/CSS/JS/JSON); il browser DECOMPRIME automaticamente la risposta (header 'Content-Encoding: gzip') in modo trasparente per l'utente/JavaScript - un'ottimizzazione comune per migliorare i tempi di caricamento, specialmente su connessioni lente." },
      { id:68, type:"mc", topic:"Testing", text:"Cosa rappresenta un 'test di integrazione' per un'applicazione web, rispetto a un 'unit test'?", options:["Un test di integrazione verifica che PIÙ COMPONENTI (es. codice applicativo + database REALE, o più endpoint API in sequenza) FUNZIONINO CORRETTAMENTE INSIEME; un unit test verifica una SINGOLA FUNZIONE/COMPONENTE in ISOLAMENTO (spesso con dipendenze 'mockate')", "Sono sinonimi identici", "I test di integrazione non richiedono mai un database", "Un unit test verifica sempre l'intera applicazione end-to-end"], correct:0, explanation:"UNIT TEST: testa una SINGOLA unità di codice (es. una funzione 'calcolaSconto($prezzo, $percentuale)') in ISOLAMENTO, spesso 'mockando' (simulando) dipendenze esterne come il database, per essere VELOCE e mirato a una logica specifica. TEST DI INTEGRAZIONE: verifica che diverse PARTI del sistema funzionino CORRETTAMENTE QUANDO COMBINATE - es. che una richiesta POST /api/ordini effettivamente INSERISCA una riga nel database REALE (o in un database di test), che un endpoint richieda autenticazione, che il flusso completo 'crea utente -> login -> crea ordine' funzioni; sono più LENTI ma catturano problemi di INTERAZIONE tra componenti che gli unit test (con dipendenze mockate) non rileverebbero." },
      { id:69, type:"mc", topic:"Sicurezza file upload", text:"Perché controllare SOLO l'estensione del file (es. '.jpg') NON è sufficiente per validare un upload di immagine in modo sicuro?", options:["L'estensione del file è facilmente FALSIFICABILE da un attaccante (es. rinominare 'malware.php' in 'malware.jpg'); è necessario verificare anche il CONTENUTO REALE del file (MIME type effettivo, 'magic bytes'/firma del file) e, idealmente, rielaborare l'immagine (es. con una libreria di image processing)", "Controllare l'estensione è sufficiente e sicuro al 100%", "I file con estensione .jpg non possono mai contenere codice eseguibile, per definizione", "Il controllo dell'estensione è un controllo che il sistema operativo fa automaticamente, l'applicazione non deve fare nulla"], correct:0, explanation:"Un attaccante può creare un file che contiene CODICE PHP MALEVOLO ma con NOME 'immagine.jpg' (o anche 'immagine.php.jpg' su configurazioni server vulnerabili che eseguono comunque l'ultima estensione 'doppia'); se il server poi ESEGUE quel file come PHP (es. se è stato salvato in una cartella accessibile via web e il server è configurato a eseguire .php anche con doppia estensione), si ottiene ESECUZIONE DI CODICE REMOTO. DIFESE: verificare il MIME TYPE EFFETTIVO del contenuto (non il nome dichiarato), verificare le 'magic bytes' (i primi byte di un file JPG reale hanno una firma specifica), RINOMINARE il file con un nome generato dal server (non controllato dall'utente), salvare gli upload FUORI dalla cartella servita direttamente dal web server, e idealmente RI-ELABORARE l'immagine (ridimensionamento) con una libreria, che fallirebbe su un file che non è realmente un'immagine valida." },
      { id:70, type:"mc", topic:"Sessioni", text:"Cosa succede tipicamente quando un utente effettua il LOGOUT da un'applicazione web basata su sessioni server-side (PHP)?", options:["La sessione lato server viene DISTRUTTA (es. session_destroy() in PHP) e il cookie di sessione lato client viene invalidato/rimosso, in modo che richieste SUCCESSIVE con quel cookie NON vengano più associate a un utente autenticato", "Il database dell'applicazione viene cancellato completamente", "L'utente non potrà mai più effettuare il login con lo stesso account", "Il logout cambia automaticamente la password dell'utente"], correct:0, explanation:"Il logout deve invalidare la sessione SERVER-SIDE (cancellando i dati di sessione associati a quell'id, es. session_destroy() in PHP, che elimina anche il file/record di sessione sul server) E, idealmente, rimuovere/invalidare il COOKIE di sessione lato client (es. impostando un cookie con scadenza nel passato); se si invalidasse SOLO il cookie client-side ma i dati di sessione rimanessero VALIDI sul server, un attaccante in possesso del VECCHIO valore del cookie (es. intercettato prima del logout) potrebbe ancora usarlo per impersonare l'utente." },
      { id:71, type:"mc", topic:"Architettura a microservizi", text:"Qual è una caratteristica distintiva dell'architettura a 'microservizi' rispetto a un'applicazione 'monolitica'?", options:["L'applicazione è SUDDIVISA in PIÙ SERVIZI INDIPENDENTI, ciascuno responsabile di una funzionalità specifica (es. 'servizio utenti', 'servizio ordini', 'servizio pagamenti'), che comunicano tra loro tramite rete (API/messaggi), e possono essere SVILUPPATI, DEPLOYATI e SCALATI INDIPENDENTEMENTE", "I microservizi sono semplicemente versioni 'più piccole' dello stesso identico codice monolitico", "Un'architettura a microservizi non può mai usare un database", "I microservizi eliminano completamente la necessità di API"], correct:0, explanation:"In un MONOLITE, tutte le funzionalità (gestione utenti, ordini, pagamenti, notifiche) sono parte di UN'UNICA applicazione/codebase, deployata come UN'unica unità. Nei MICROSERVIZI, ciascuna funzionalità diventa un SERVIZIO SEPARATO con il proprio database (spesso) e API, comunicando con gli altri servizi via rete (HTTP/messaggistica); VANTAGGI: team diversi possono lavorare su servizi diversi indipendentemente, ogni servizio può essere SCALATO separatamente (es. 'servizio pagamenti' replicato di più durante i saldi), tecnologie diverse per servizi diversi; SVANTAGGI: maggiore COMPLESSITÀ OPERATIVA (deployment, monitoraggio, comunicazione di rete tra servizi, gestione di fallimenti parziali)." },
      { id:72, type:"open", topic:"Riepilogo sicurezza", text:"Elenca e descrivi brevemente 3 vulnerabilità della OWASP Top 10 (oltre a SQL Injection e XSS, già trattate altrove) rilevanti per un'applicazione web PHP/MySQL, e una contromisura per ciascuna.", modelAnswer:"1) BROKEN AUTHENTICATION (Autenticazione debole/compromessa): include problemi come password debolmente hashate (o in chiaro), assenza di limiti sui tentativi di login (permettendo attacchi brute-force), session id predicibili. CONTROMISURA: usare password_hash()/password_verify() (bcrypt) per le password, implementare rate-limiting sui tentativi di login (es. blocco temporaneo dopo N tentativi falliti), usare session_regenerate_id() dopo il login. 2) INSECURE DIRECT OBJECT REFERENCES / BROKEN ACCESS CONTROL: si verifica quando un'applicazione usa un identificatore (es. id di un ordine nell'URL '/ordine.php?id=42') SENZA VERIFICARE che l'utente AUTENTICATO sia effettivamente AUTORIZZATO ad accedere a QUELLA risorsa specifica - un utente potrebbe modificare l'id nell'URL (es. id=43) e accedere ai dati di UN ALTRO utente. CONTROMISURA: per OGNI richiesta a una risorsa specifica, verificare lato server che 'id_risorsa appartenga all'utente loggato' (es. 'WHERE id=? AND id_utente=?'), non fidandosi del solo id ricevuto. 3) SECURITY MISCONFIGURATION: include errori di configurazione come messaggi di errore PHP con STACK TRACE COMPLETI mostrati in produzione (rivelando percorsi/versioni/struttura del codice), credenziali di default non cambiate, directory listing abilitato. CONTROMISURA: in produzione, impostare 'display_errors = Off' e loggare gli errori SOLO su file (non mostrarli all'utente), disabilitare il directory listing del web server, cambiare TUTTE le credenziali di default.", keywords:["Broken Authentication: password hashing debole/assente, mancanza di rate-limiting sul login - contromisura: password_hash/bcrypt e limiti sui tentativi", "Broken Access Control / IDOR: accesso a risorse di altri utenti modificando un id nell'URL - contromisura: verificare lato server che la risorsa appartenga all'utente autenticato", "Security Misconfiguration: stack trace/errori PHP visibili in produzione - contromisura: display_errors Off e logging su file"] },
      { id:73, type:"mc", topic:"Routing", text:"Cosa rappresenta un 'URL friendly' (o 'slug'), es. /articoli/come-imparare-php invece di /articolo.php?id=42?", options:["Una rappresentazione dell'URL più LEGGIBILE per gli ESSERI UMANI e migliore per la SEO (motori di ricerca), tipicamente implementata tramite riscrittura degli URL (URL rewriting, es. con mod_rewrite di Apache) che internamente mappa l'URL 'pulito' a un controller/query effettivi", "Un URL che funziona solo su dispositivi mobili", "Un sinonimo di indirizzo IP del server", "Un URL che contiene sempre un token di sicurezza"], correct:0, explanation:"Gli URL 'friendly' (es. '/prodotti/scarpe-running-modello-x') sono più LEGGIBILI, MEMORIZZABILI, e i motori di ricerca tendono a considerarli più rilevanti (le parole nell'URL possono corrispondere a termini di ricerca) rispetto a '/prodotto.php?id=12345'; vengono implementati con URL REWRITING (regole nel web server, es. .htaccess con mod_rewrite, che traducono '/prodotti/scarpe-running-modello-x' internamente in qualcosa come 'prodotto.php?slug=scarpe-running-modello-x', che poi la query SQL traduce nell'id effettivo tramite una colonna 'slug' nel database)." },
      { id:74, type:"mc", topic:"Variabili PHP", text:"Qual è la differenza tra le superglobali $_GET, $_POST e $_REQUEST in PHP?", options:["$_GET contiene i parametri passati nella QUERY STRING dell'URL; $_POST contiene i dati inviati nel BODY di una richiesta POST (es. da un form); $_REQUEST contiene un COMBINAZIONE di $_GET, $_POST (e $_COOKIE), generalmente SCONSIGLIATO per ambiguità sull'origine del dato", "Sono tre nomi diversi per la stessa identica variabile", "$_GET contiene solo numeri, $_POST solo stringhe", "$_REQUEST è disponibile solo in PHP 8+"], correct:0, explanation:"$_GET['param'] legge i valori dalla query string (es. '?param=valore' nell'URL); $_POST['campo'] legge i dati inviati nel BODY di una richiesta con method='POST' (tipicamente da form HTML); $_REQUEST è una FUSIONE di $_GET, $_POST e $_COOKIE - il suo uso è generalmente SCONSIGLIATO perché non è chiaro DA DOVE provenga un determinato valore (un attaccante potrebbe inviare un parametro sia via GET sia via POST per influenzare $_REQUEST in modi inattesi), preferendo accedere esplicitamente a $_GET o $_POST in base al metodo previsto." },
      { id:75, type:"mc", topic:"Statelessness", text:"Cosa significa che le API REST dovrebbero essere 'stateless' (senza stato)?", options:["OGNI richiesta dal client al server deve contenere TUTTE le informazioni necessarie per essere elaborata (es. token di autenticazione), SENZA che il server debba mantenere/ricordare informazioni sullo STATO del client tra una richiesta e l'altra (a differenza delle sessioni server-side tradizionali)", "Le API stateless non possono mai restituire dati", "Stateless significa che l'API non usa mai HTTPS", "Le API stateless non possono autenticare gli utenti"], correct:0, explanation:"In un'API STATELESS (tipica filosofia REST, spesso usando token JWT invece di session id), il server NON conserva 'memoria' tra le richieste di un client: ogni richiesta è AUTOSUFFICIENTE, includendo es. un token JWT nell'header Authorization che il server può VALIDARE e da cui può estrarre l'identità dell'utente, SENZA dover consultare uno 'storage di sessioni'; questo facilita la SCALABILITÀ (qualsiasi server replica può gestire qualsiasi richiesta, senza bisogno di 'session affinity' verso un server specifico)." },
      { id:76, type:"open", topic:"Deploy", text:"Spiega la differenza tra ambiente di 'sviluppo' (development), 'staging' (o test) e 'produzione' (production) in un workflow di sviluppo web, e perché è importante NON testare modifiche direttamente in produzione.", modelAnswer:"AMBIENTE DI SVILUPPO (development/local): l'ambiente sul computer dello SVILUPPATORE, dove il codice viene scritto e testato inizialmente; spesso con dati 'finti'/di esempio, configurazioni di debug attive (mostra errori dettagliati), e nessun impatto su utenti reali. AMBIENTE DI STAGING (o test/pre-produzione): una COPIA dell'ambiente di produzione (stessa configurazione server, versione PHP/MySQL, ecc.) ma SEPARATA, usata per testare le modifiche in un contesto REALISTICO PRIMA di rilasciarle agli utenti finali - permette di individuare problemi che NON si manifestano in locale (es. differenze di configurazione, dati con volumi maggiori, integrazione con servizi esterni reali). AMBIENTE DI PRODUZIONE (production): l'ambiente USATO DAGLI UTENTI REALI, con dati REALI; qualsiasi errore qui ha un IMPATTO DIRETTO sugli utenti (perdita di dati, downtime, esposizione di dati sensibili tramite bug). PERCHÉ NON TESTARE DIRETTAMENTE IN PRODUZIONE: (1) un BUG non rilevato potrebbe CORROMPERE DATI REALI (es. una query UPDATE/DELETE errata su dati di clienti veri, IRREVERSIBILE senza backup); (2) potrebbe causare DOWNTIME (interruzione del servizio) per gli utenti; (3) errori 'temporanei' durante il test sarebbero VISIBILI agli utenti reali (messaggi di errore, malfunzionamenti), danneggiando la fiducia/reputazione. Il workflow corretto è: sviluppo -> test in staging (con dati simili alla produzione ma non reali, o copie anonimizzate) -> se tutto funziona, deploy in produzione, idealmente con possibilità di ROLLBACK rapido in caso di problemi imprevisti.", keywords:["sviluppo: ambiente locale dello sviluppatore con dati di esempio e debug attivo", "staging: copia dell'ambiente di produzione usata per testare in un contesto realistico prima del rilascio", "produzione: ambiente usato dagli utenti reali con dati reali, errori hanno impatto diretto", "rischi del testare in produzione: corruzione dati reali, downtime, esposizione di errori agli utenti", "workflow corretto: sviluppo -> staging -> produzione, con possibilita' di rollback"] },
      { id:77, type:"mc", topic:"Cookie", text:"Cosa indica l'attributo 'Expires' (o 'Max-Age') di un cookie HTTP?", options:["Specifica per QUANTO TEMPO il cookie deve essere CONSERVATO dal browser; se omesso, il cookie è un 'session cookie' che viene eliminato alla CHIUSURA del browser", "Indica il numero massimo di volte che il cookie può essere letto", "Indica la dimensione massima in byte del cookie", "Forza il cookie a essere sempre HTTPS"], correct:0, explanation:"Un cookie SENZA 'Expires'/'Max-Age' è un 'session cookie': esiste solo per la DURATA della sessione del browser (eliminato alla chiusura); impostando 'Expires=data_futura' (o 'Max-Age=secondi'), il cookie diventa 'persistente' e viene CONSERVATO dal browser fino a quella data (anche dopo la chiusura/riapertura del browser), utile per funzionalità come 'ricordami' nel login, ma con implicazioni di PRIVACY/sicurezza se usato per dati sensibili." },
      { id:78, type:"mc", topic:"GraphQL vs REST", text:"Qual è una differenza concettuale tra un'API REST tradizionale e GraphQL?", options:["In REST, ogni 'endpoint' restituisce una struttura FISSA di dati predefinita dal server; in GraphQL, il CLIENT specifica ESATTAMENTE quali CAMPI/RELAZIONI desidera in UNA SINGOLA richiesta, e il server restituisce SOLO quei dati, potenzialmente combinando informazioni che in REST richiederebbero più endpoint/richieste", "GraphQL è semplicemente un sinonimo di REST con un nome diverso", "REST non può restituire dati in formato JSON, solo XML", "GraphQL funziona solo con database NoSQL"], correct:0, explanation:"In REST, '/api/utenti/5' potrebbe restituire SEMPRE TUTTI i campi dell'utente (anche se il client ne usa solo alcuni - 'over-fetching'), e per ottenere anche i suoi ordini si servirebbe una richiesta SEPARATA a '/api/utenti/5/ordini' ('under-fetching' che richiede multiple richieste); con GraphQL, il client invia una QUERY che specifica esattamente: 'voglio nome ed email dell'utente 5, E i titoli (solo i titoli) dei suoi ultimi 3 ordini' - il server elabora questa richiesta e restituisce ESATTAMENTE quei dati in UNA risposta, riducendo sia over-fetching che il numero di round-trip di rete." },
      { id:79, type:"mc", topic:"Encoding URL", text:"Perché uno spazio in un parametro URL (es. in una query string) viene tipicamente codificato come '%20' o '+'?", options:["Gli URL hanno un set di caratteri 'sicuri' permessi senza codifica; caratteri come spazi (e altri caratteri speciali) devono essere CODIFICATI in 'percent-encoding' (es. spazio = %20) per essere trasmessi correttamente all'interno di un URL senza ambiguità", "Lo spazio non può mai apparire in un URL per nessun motivo", "%20 indica un errore nell'URL", "La codifica serve solo per ragioni estetiche, senza impatto funzionale"], correct:0, explanation:"La specifica degli URL definisce un set di caratteri 'riservati'/'non sicuri' (spazi, '&', '=', '?', caratteri non-ASCII, ecc.) che, se presenti LETTERALMENTE in un URL, potrebbero essere interpretati AMBIGUAMENTE (es. uno spazio potrebbe terminare l'URL in alcuni contesti, '&' separa parametri nella query string); funzioni come 'urlencode()' in PHP (o 'encodeURIComponent()' in JavaScript) convertono questi caratteri in 'percent-encoding' (es. spazio -> %20 o +, '&' -> %26), garantendo che il valore venga interpretato come DATO e non come SINTASSI dell'URL." },
      { id:80, type:"mc", topic:"Database vs file storage", text:"Per memorizzare FILE caricati dagli utenti (es. immagini profilo, documenti PDF) in un'applicazione web, qual è generalmente l'approccio PREFERIBILE rispetto a salvarli direttamente come BLOB nel database?", options:["Salvare i FILE su un FILESYSTEM (o servizio di storage dedicato, es. cloud storage) e memorizzare nel DATABASE solo il PERCORSO/RIFERIMENTO al file, mantenendo il database più 'leggero' e ottimizzato per query relazionali, e il filesystem/storage ottimizzato per il serving di file statici", "Salvare sempre i file come BLOB nel database, è l'unico approccio possibile", "I file non possono mai essere memorizzati in un'applicazione web", "Salvare i file come stringhe Base64 in una colonna VARCHAR è sempre la scelta migliore"], correct:0, explanation:"Memorizzare file BINARI grandi (immagini, PDF, video) DIRETTAMENTE nel database (come BLOB) ha SVANTAGGI: aumenta drasticamente la dimensione del database (impattando backup, performance delle query, cache); il database NON è ottimizzato per il 'serving' efficiente di file statici (a differenza di un web server o CDN); query SELECT * su tabelle con BLOB grandi diventano più lente. L'approccio PREFERITO è salvare il file su FILESYSTEM (o storage cloud come S3) con un NOME/PERCORSO generato in modo sicuro, e memorizzare nel database SOLO una colonna VARCHAR con il percorso/URL del file, mantenendo i due 'tipi' di dato nei sistemi più adatti a gestirli." },
      { id:81, type:"mc", topic:"Tempo di risposta", text:"Cosa misura tipicamente la metrica 'Time To First Byte' (TTFB) di una pagina web?", options:["Il tempo che intercorre tra l'INVIO della richiesta HTTP da parte del browser e la RICEZIONE del PRIMO BYTE della risposta dal server - include il tempo di elaborazione lato server (es. query al database) e la latenza di rete", "Il tempo totale per scaricare TUTTE le risorse della pagina (immagini, CSS, JS)", "Il numero di byte totali della pagina", "Il tempo che l'utente impiega a leggere la pagina"], correct:0, explanation:"TTFB è un indicatore PRECOCE delle performance: un TTFB elevato suggerisce che il SERVER impiega molto tempo a GENERARE la risposta (es. query SQL lente, mancanza di cache, elaborazione server-side pesante), prima ancora che il browser inizi a scaricare/renderizzare il contenuto; un TTFB basso è importante per la PERCEZIONE di 'velocità' del sito da parte dell'utente, ed è anche un fattore considerato da alcuni motori di ricerca per il ranking SEO." },
      { id:82, type:"mc", topic:"Idempotenza", text:"Cosa significa che un metodo HTTP è 'idempotente'?", options:["Eseguire la STESSA richiesta MULTIPLE VOLTE produce lo STESSO EFFETTO sullo stato del server di eseguirla UNA SOLA VOLTA (es. GET, PUT, DELETE sono considerati idempotenti; POST generalmente NON lo è)", "Il metodo non può mai fallire", "Idempotente significa che il metodo è il più rapido tra tutti", "Solo i metodi idempotenti possono restituire JSON"], correct:0, explanation:"GET (lettura, non modifica nulla) è naturalmente idempotente; PUT /utenti/5 con {nome:'Mario'} eseguito 1 o 10 volte produce lo STESSO stato finale (l'utente 5 si chiama 'Mario'); DELETE /utenti/5 eseguito 1 o più volte risulta nello stesso stato finale (l'utente 5 non esiste - anche se la SECONDA chiamata potrebbe restituire 404 invece di 200/204, lo STATO del server è equivalente). POST /ordini (crea un NUOVO ordine) NON è idempotente: eseguirlo 2 volte crea 2 ordini DIVERSI - questo è importante per decidere se un client può SICURAMENTE RI-TENTARE (retry) una richiesta in caso di timeout/errore di rete senza causare effetti duplicati indesiderati." },
      { id:83, type:"open", topic:"Riepilogo HTTP", text:"Descrivi il percorso completo di una richiesta dal click su un link <a href='/prodotti'> fino alla visualizzazione della pagina nel browser, menzionando DNS, TCP, HTTP request/response, e rendering.", modelAnswer:"1) RISOLUZIONE DNS: il browser deve tradurre il nome di dominio (es. 'www.negozio.it') nell'INDIRIZZO IP del server che lo ospita - interroga un server DNS (spesso con cache a vari livelli: browser, sistema operativo, router, provider) per ottenere questo indirizzo. 2) CONNESSIONE TCP (e TLS per HTTPS): il browser stabilisce una connessione TCP (three-way handshake: SYN, SYN-ACK, ACK) con il server all'indirizzo IP ottenuto, sulla porta 443 (HTTPS) o 80 (HTTP); per HTTPS, segue un handshake TLS per stabilire una connessione CIFRATA. 3) RICHIESTA HTTP: il browser invia una richiesta 'GET /prodotti HTTP/1.1' con vari header (Host, Cookie, Accept, User-Agent, ecc.) attraverso la connessione stabilita. 4) ELABORAZIONE SERVER-SIDE: il server (es. Apache+PHP) riceve la richiesta, il ROUTING determina quale 'controller'/script gestisce '/prodotti', che potrebbe interrogare il DATABASE (es. SELECT * FROM Prodotti) per ottenere i dati necessari, e genera dinamicamente l'HTML della risposta (o restituisce JSON, per API). 5) RISPOSTA HTTP: il server invia una risposta 'HTTP/1.1 200 OK' con header (Content-Type, Content-Length, ecc.) e il BODY (l'HTML generato). 6) PARSING E RENDERING: il browser RICEVE l'HTML e inizia a 'parsarlo', costruendo il DOM; durante il parsing, scopre RIFERIMENTI a risorse aggiuntive (CSS, JS, immagini) e avvia richieste AGGIUNTIVE (ognuna seguendo potenzialmente passi simili 1-5, anche se spesso riutilizzando connessioni esistenti) per scaricarle; il browser applica il CSS (CSSOM), esegue il JavaScript, e infine RENDERIZZA la pagina visivamente sullo schermo (layout + paint).", keywords:["DNS: risoluzione del nome di dominio in indirizzo IP", "TCP/TLS: stabilimento della connessione (handshake TCP, e TLS per HTTPS)", "richiesta HTTP GET con header verso il server", "elaborazione server-side: routing, query al database, generazione dell'HTML", "risposta HTTP con status code e body", "parsing/rendering: costruzione del DOM, richieste per risorse aggiuntive (CSS/JS/immagini), rendering finale"] },
      { id:84, type:"mc", topic:"Sicurezza password", text:"Perché si usa un 'salt' (sale) quando si memorizza l'hash di una password (es. con password_hash() in PHP)?", options:["Il salt è un valore ALEATORIO, UNICO per ciascuna password, COMBINATO con la password PRIMA dell'hashing; questo garantisce che PASSWORD IDENTICHE produciano HASH DIVERSI, impedendo l'uso di tabelle precalcolate (rainbow table) per individuare password comuni a partire dagli hash", "Il salt rende la password più lunga visivamente all'utente", "Il salt serve solo a velocizzare il processo di hashing", "Il salt è un sinonimo di 'password in chiaro'"], correct:0, explanation:"Senza salt, se due utenti diversi scegliessero la STESSA password (es. '123456'), avrebbero lo STESSO hash nel database - un attaccante con accesso a una 'rainbow table' (hash precalcolati per password comuni) potrebbe IDENTIFICARE rapidamente quegli hash; il salt (generato CASUALMENTE per ogni password, e tipicamente memorizzato INSIEME all'hash, non segreto) fa sì che 'password123' + salt_A produca un hash DIVERSO da 'password123' + salt_B, rendendo le rainbow table INUTILI (l'attaccante dovrebbe calcolare una tabella SEPARATA per ogni salt, computazionalmente proibitivo). password_hash() di PHP gestisce automaticamente la generazione e l'inclusione del salt nell'hash risultante." },
      { id:85, type:"mc", topic:"Eventi e listener", text:"Quale evento JavaScript è appropriato per eseguire codice DOPO che l'utente ha selezionato un file in un campo <input type='file'>, ma PRIMA dell'eventuale submit del form (es. per mostrare un'anteprima dell'immagine)?", options:["L'evento 'change' sull'elemento <input type='file'>", "L'evento 'submit' sul <form>", "L'evento 'load' sulla finestra (window)", "L'evento 'click' sul tag <body>"], correct:0, explanation:"L'evento 'change' su un <input type='file'> si attiva quando l'utente SELEZIONA (o cambia) il file scelto tramite la finestra di dialogo del sistema operativo; nel listener, si può accedere a 'input.files[0]' per ottenere informazioni sul file (nome, dimensione, tipo) e, usando 'FileReader' (API JavaScript), leggere il CONTENUTO del file per mostrare un'ANTEPRIMA (es. impostando 'src' di un <img> con un data URL) PRIMA che il form venga effettivamente inviato al server." },
      { id:86, type:"mc", topic:"Errori HTTP 5xx vs 4xx", text:"Qual è la differenza concettuale tra un codice di stato HTTP nella fascia 4xx (es. 404, 400) e uno nella fascia 5xx (es. 500, 503)?", options:["I codici 4xx indicano un problema lato CLIENT (es. risorsa non trovata, richiesta malformata, non autorizzato); i codici 5xx indicano un problema lato SERVER (es. errore interno nell'elaborazione, servizio temporaneamente non disponibile), generalmente NON causato da un errore del client", "4xx e 5xx sono completamente intercambiabili", "4xx indica sempre successo, 5xx indica sempre fallimento", "I codici 5xx vengono restituiti solo da database, non da web server"], correct:0, explanation:"4xx ('client error'): la richiesta del CLIENT ha un PROBLEMA - 404 (risorsa non trovata, es. URL sbagliato), 400 (richiesta malformata, es. JSON non valido), 401 (non autenticato), 403 (autenticato ma non autorizzato); il client dovrebbe CORREGGERE la richiesta. 5xx ('server error'): il SERVER ha incontrato un problema NELL'ELABORARE una richiesta CHE ERA VALIDA - 500 (errore interno generico, es. un'eccezione PHP non gestita), 503 (servizio temporaneamente non disponibile, es. in manutenzione o sovraccarico); il client generalmente NON può 'correggere' un 5xx modificando la richiesta - il problema è lato server." },
      { id:87, type:"open", topic:"Architettura completa", text:"Descrivi, ad alto livello, l'architettura completa (componenti principali e come comunicano) di un'applicazione web e-commerce moderna basata su PHP, MySQL e JavaScript, includendo la gestione delle sessioni utente, la sicurezza dei pagamenti, e la struttura del database per prodotti/ordini.", modelAnswer:"COMPONENTI PRINCIPALI: (1) FRONTEND (browser): HTML/CSS per la struttura/stile, JavaScript per interattività (es. aggiungere prodotti al carrello via AJAX/fetch senza ricaricare la pagina, validazione form lato client per UX). (2) BACKEND (server PHP): gestisce le richieste, implementa la LOGICA DI BUSINESS (calcolo prezzi/sconti, gestione carrello, elaborazione ordini), comunica con il database, genera risposte HTML o JSON (per chiamate AJAX). (3) DATABASE (MySQL): tabelle principali - Prodotti(id, nome, prezzo, quantita_disponibile, descrizione), Utenti(id, email, password_hash, ...), Ordini(id, id_utente, data, stato, totale), DettagliOrdine(id_ordine, id_prodotto, quantita, prezzo_unitario) - con FOREIGN KEY per garantire integrità referenziale. GESTIONE SESSIONI: dopo il login (verifica email/password_hash con password_verify()), PHP avvia una sessione (session_start(), session_regenerate_id(true)) che identifica l'utente per richieste successive (es. per associare il carrello all'utente, mostrare 'I miei ordini'); il CARRELLO può essere memorizzato in sessione (per utenti non loggati) o nel database associato all'id_utente (per persistenza tra dispositivi). SICUREZZA DEI PAGAMENTI: l'applicazione NON dovrebbe gestire DIRETTAMENTE i dati della carta di credito (per compliance PCI-DSS); si integra con un GATEWAY DI PAGAMENTO ESTERNO (es. Stripe, PayPal) tramite la loro API - il frontend invia i dati della carta DIRETTAMENTE al gateway (tramite un loro script/iframe sicuro), ottenendo un TOKEN che il backend usa per AUTORIZZARE il pagamento, senza che i dati sensibili della carta TRANSITINO MAI attraverso i propri server. SICUREZZA GENERALE: HTTPS per TUTTE le comunicazioni, prepared statement per le query, validazione/sanitizzazione di tutti gli input, CSRF token sui form, principio del minimo privilegio per le credenziali del database.", keywords:["frontend (HTML/CSS/JS) per interfaccia e interattivita', backend PHP per logica di business, MySQL per dati persistenti", "tabelle Prodotti, Utenti, Ordini, DettagliOrdine con foreign key per integrita' referenziale", "gestione sessioni: login con password_hash/verify, session_regenerate_id dopo login, carrello in sessione o database", "pagamenti: integrazione con gateway esterno (es. Stripe), i dati della carta non transitano sui propri server (PCI-DSS)", "sicurezza generale: HTTPS, prepared statement, validazione input, CSRF token, minimo privilegio database"] },
      { id:88, type:"mc", topic:"Header Location", text:"Cosa fa l'header HTTP 'Location' in una risposta con status code 302 (Found/redirect temporaneo)?", options:["Indica al BROWSER l'URL verso cui deve effettuare AUTOMATICAMENTE una NUOVA richiesta (redirect), tipicamente usato dopo un form POST (es. dopo il login, reindirizzare alla dashboard) per evitare problemi di doppio submit con il tasto 'indietro'", "Indica la posizione geografica del server", "Indica dove salvare il file scaricato sul disco dell'utente", "È un header obsoleto senza alcun effetto sul browser moderno"], correct:0, explanation:"Quando un server risponde con uno status 3xx (redirect, es. 302 o 303) e un header 'Location: /dashboard', il BROWSER effettua AUTOMATICAMENTE una NUOVA richiesta GET verso '/dashboard'; questo pattern ('POST-redirect-GET') è comunemente usato dopo l'elaborazione di un form (es. login, creazione ordine): il server PROCESSA il POST, poi REDIRIGE a una pagina di 'successo' - se l'utente preme 'aggiorna' su quella pagina, il browser ri-richiede SOLO il GET della pagina di destinazione, NON ri-invia il form POST originale (evitando, ad esempio, la creazione di un ordine duplicato)." },
      { id:89, type:"mc", topic:"Encoding caratteri", text:"Perché è importante specificare la codifica dei caratteri (es. 'charset=UTF-8') sia nell'HTML (<meta charset='UTF-8'>) sia nelle connessioni al database MySQL?", options:["Per garantire che CARATTERI SPECIALI (es. accenti italiani à, è, ò, simboli come €, emoji) vengano memorizzati, trasmessi e VISUALIZZATI CORRETTAMENTE in TUTTE le fasi (input dell'utente, salvataggio nel database, visualizzazione nella pagina), evitando problemi di 'caratteri corrotti' (mojibake)", "UTF-8 serve solo per velocizzare le query SQL", "La codifica dei caratteri riguarda solo file immagine, non testo", "Senza specificare UTF-8, il sito non può usare CSS"], correct:0, explanation:"Se ci sono INCOERENZE tra le codifiche usate nelle varie fasi (es. il form HTML invia dati in UTF-8, ma la connessione al database è configurata per Latin1), caratteri come 'à' o 'è' possono venire memorizzati/letti ERRONEAMENTE, producendo simboli 'corrotti' (mojibake, es. 'Ã ' invece di 'à'); è importante che TUTTA LA CATENA (encoding HTML della pagina, charset della connessione PDO/MySQLi al database, collation delle tabelle MySQL) usi CONSISTENTEMENTE UTF-8 (idealmente utf8mb4, che supporta anche emoji e caratteri Unicode a 4 byte, a differenza del vecchio 'utf8' di MySQL limitato a 3 byte)." },
      { id:90, type:"open", topic:"Riepilogo CRUD/REST", text:"Per una risorsa 'Articolo' di un blog, descrivi come implementeresti le 4 operazioni CRUD come endpoint di un'API REST, specificando metodo HTTP, URL, e status code di risposta tipico per ciascuna.", modelAnswer:"CREATE (creare un nuovo articolo): METODO POST, URL '/api/articoli', BODY contiene i dati del nuovo articolo (titolo, contenuto, ecc.) in formato JSON; risposta tipica: STATUS 201 Created, con header 'Location: /api/articoli/{nuovo_id}' e body contenente l'articolo creato (incluso l'id generato). READ - LISTA (ottenere tutti gli articoli): METODO GET, URL '/api/articoli' (eventualmente con query string per paginazione/filtri, es. '?pagina=2&categoria=tech'); risposta: STATUS 200 OK, body JSON con un array di articoli. READ - SINGOLO (ottenere un articolo specifico): METODO GET, URL '/api/articoli/{id}'; risposta: STATUS 200 OK con i dati dell'articolo, oppure STATUS 404 Not Found se l'id non esiste. UPDATE (modificare un articolo esistente): METODO PUT (sostituzione completa) o PATCH (modifica parziale), URL '/api/articoli/{id}', BODY con i nuovi dati; risposta: STATUS 200 OK con l'articolo aggiornato (o 204 No Content se non si restituisce body), oppure 404 se l'id non esiste. DELETE (eliminare un articolo): METODO DELETE, URL '/api/articoli/{id}'; risposta: STATUS 204 No Content (eliminazione riuscita, nessun body da restituire) oppure 404 se l'id non esiste. In TUTTI i casi, se l'utente non è AUTENTICATO/AUTORIZZATO per l'operazione (es. solo l'autore può modificare/eliminare il proprio articolo), si risponde con 401 (non autenticato) o 403 (autenticato ma non autorizzato).", keywords:["CREATE: POST /api/articoli, status 201 Created con Location header", "READ lista: GET /api/articoli, status 200 con array JSON", "READ singolo: GET /api/articoli/{id}, status 200 o 404", "UPDATE: PUT/PATCH /api/articoli/{id}, status 200 o 404", "DELETE: DELETE /api/articoli/{id}, status 204 o 404", "401/403 per problemi di autenticazione/autorizzazione su qualsiasi operazione"] },
      { id:91, type:"mc", topic:"Logging", text:"Perché è buona pratica REGISTRARE (log) gli errori di un'applicazione web in un FILE (o sistema di logging dedicato) invece di mostrarli direttamente all'utente in produzione?", options:["I log permettono agli SVILUPPATORI/amministratori di DIAGNOSTICARE problemi (analizzando stack trace, query fallite, ecc.) SENZA esporre informazioni SENSIBILI sulla struttura interna dell'applicazione (percorsi file, versioni software, query SQL) agli UTENTI FINALI (o potenziali attaccanti)", "I log servono solo a riempire spazio su disco senza utilità", "Mostrare errori dettagliati agli utenti migliora sempre la loro esperienza", "Il logging è richiesto solo per applicazioni che non usano database"], correct:0, explanation:"Un messaggio di errore PHP non gestito (es. con display_errors=On) potrebbe mostrare all'utente lo STACK TRACE completo, inclusi PERCORSI DI FILE sul server, la QUERY SQL che ha causato l'errore (potenzialmente rivelando struttura delle tabelle), o VERSIONI di software usate - informazioni PREZIOSE per un attaccante che pianifica un attacco mirato; in PRODUZIONE, gli errori dovrebbero essere SCRITTI in un file di LOG (accessibile solo agli amministratori) con TUTTI i dettagli utili per il DEBUG, mentre all'utente viene mostrato un messaggio GENERICO ('Si è verificato un errore, riprova più tardi')." },
      { id:92, type:"mc", topic:"Differenza tra HTTP/1.1 e HTTP/2", text:"Quale miglioramento introduce HTTP/2 rispetto a HTTP/1.1 per quanto riguarda il caricamento di MULTIPLE risorse (CSS, JS, immagini) da uno stesso server?", options:["HTTP/2 supporta il 'multiplexing': MULTIPLE richieste e risposte possono essere INVIATE/RICEVUTE CONTEMPORANEAMENTE su un'UNICA connessione TCP, eliminando la necessità di aprire connessioni multiple (o di tecniche come 'concatenare' file CSS/JS per ridurre il numero di richieste) per migliorare le performance", "HTTP/2 elimina completamente la necessità del protocollo TCP", "HTTP/2 funziona solo per immagini, non per file CSS/JS", "HTTP/2 è identico a HTTP/1.1, solo con un numero di versione diverso"], correct:0, explanation:"In HTTP/1.1, ogni connessione TCP poteva gestire le richieste in modo limitato (con 'pipelining' problematico in pratica), portando i browser ad apri MULTIPLE connessioni parallele verso lo stesso server (con un limite, es. 6 per dominio) per scaricare risorse in parallelo, e gli sviluppatori a tecniche come 'concatenare' più file CSS/JS in uno solo per RIDURRE il numero di richieste HTTP necessarie. HTTP/2 introduce il MULTIPLEXING: su UNA SOLA connessione TCP, MOLTEPLICI richieste/risposte vengono interfogliate e gestite in parallelo, rendendo MENO necessarie alcune di queste 'ottimizzazioni manuali' (anche se altre best practice rimangono rilevanti)." },
      { id:93, type:"mc", topic:"Two-Factor Authentication", text:"Cosa rappresenta l'autenticazione a due fattori (2FA/MFA) come misura di sicurezza aggiuntiva al login?", options:["Richiede all'utente di fornire un SECONDO elemento di verifica (oltre alla password), tipicamente qualcosa che POSSIEDE (es. un codice generato da un'app sul telefono, o inviato via SMS) - in modo che, anche se la PASSWORD viene COMPROMESSA (es. tramite phishing o data breach), l'attaccante NON possa accedere SENZA anche il secondo fattore", "2FA significa che l'utente deve inserire la password due volte di seguito", "2FA elimina completamente la necessità di una password", "2FA è richiesto solo per applicazioni che gestiscono pagamenti"], correct:0, explanation:"I 'fattori' di autenticazione si classificano tipicamente in: 'qualcosa che SAI' (password), 'qualcosa che HAI' (telefono con app di autenticazione, token hardware, SMS), 'qualcosa che SEI' (impronta digitale, riconoscimento facciale); 2FA combina almeno DUE categorie diverse - tipicamente password (sai) + codice temporaneo da app/SMS (hai); anche se un attaccante ottiene la password (es. tramite un data breach su un altro sito dove l'utente riutilizza la stessa password), NON potrebbe completare il login senza ANCHE il secondo fattore, che l'attaccante tipicamente non possiede." },
      { id:94, type:"mc", topic:"Sviluppo", text:"Cosa rappresenta un 'framework' come Laravel (PHP) o Express (Node.js) rispetto a scrivere un'applicazione web 'da zero' (vanilla)?", options:["Un framework fornisce una STRUTTURA PREDEFINITA e COMPONENTI RIUTILIZZABILI (routing, ORM per il database, gestione sessioni, templating, validazione, protezione CSRF già integrata, ecc.), accelerando lo sviluppo e promuovendo BEST PRACTICE, a costo di una certa 'curva di apprendimento' e dipendenza dalle convenzioni del framework", "Un framework è un sinonimo di linguaggio di programmazione", "Un framework elimina completamente la necessità di scrivere codice", "I framework funzionano solo per applicazioni che non usano database"], correct:0, explanation:"Scrivere 'da zero' (PHP 'vanilla') richiede di implementare MANUALMENTE routing, gestione sessioni, accesso al database (query dirette), protezione da CSRF/XSS, validazione, ecc. - flessibile ma RIPETITIVO e a rischio di DIMENTICARE misure di sicurezza importanti; un framework fornisce queste funzionalità GIÀ IMPLEMENTATE (e generalmente TESTATE/sicure), una STRUTTURA standard per organizzare il codice (es. pattern MVC), e un ECOSISTEMA di librerie/estensioni - permettendo agli sviluppatori di concentrarsi sulla LOGICA SPECIFICA dell'applicazione invece di reinventare funzionalità comuni." },
      { id:95, type:"open", topic:"Riepilogo finale", text:"Sintetizza in che modo i concetti di 'separazione delle responsabilità' (separation of concerns) si applicano a un'applicazione web PHP/MySQL/JavaScript, citando ALMENO 3 esempi concreti di 'separazione' a diversi livelli.", modelAnswer:"La 'separazione delle responsabilità' è un principio per cui CIASCUNA PARTE di un sistema dovrebbe occuparsi di UN ASPETTO SPECIFICO, riducendo le DIPENDENZE tra parti e facilitando manutenzione/test. ESEMPI CONCRETI: (1) SEPARAZIONE TRA STRUTTURA, STILE E COMPORTAMENTO (frontend): HTML si occupa della STRUTTURA/contenuto della pagina, CSS dello STILE/presentazione visiva, JavaScript del COMPORTAMENTO/interattività - mescolare questi (es. stili 'inline' ovunque, JavaScript 'inline' negli attributi onclick) rende il codice difficile da mantenere/riusare; mantenerli separati (file .css, .js distinti) permette, ad esempio, di cambiare il TEMA visivo di un sito modificando SOLO il CSS, senza toccare HTML/JS. (2) PATTERN MVC (backend): il MODEL si occupa dei DATI e della logica di accesso al database (query SQL, validazione dei dati a livello di business), la VIEW si occupa della PRESENTAZIONE (template HTML, senza logica di business), il CONTROLLER coordina: riceve la richiesta, chiama il Model per i dati necessari, passa i dati alla View appropriata - questo permette, ad esempio, di CAMBIARE la query SQL nel Model SENZA dover toccare il template HTML, o di riutilizzare lo stesso Model per generare sia una pagina HTML sia una risposta JSON per un'API. (3) SEPARAZIONE FRONTEND/BACKEND tramite API: il backend (PHP) si occupa SOLO della logica di business e dei dati (esposti come API JSON), mentre il frontend (JavaScript) si occupa SOLO della presentazione e interazione con l'utente, comunicando con il backend tramite chiamate HTTP/AJAX - questo permette, ad esempio, di sviluppare un'app mobile che usa LA STESSA API backend, senza duplicare la logica di business.", keywords:["separazione HTML/CSS/JS: struttura, stile e comportamento in file/responsabilita' distinte", "pattern MVC: Model (dati/logica), View (presentazione), Controller (coordinamento) come responsabilita' separate", "separazione frontend/backend tramite API: backend esposto come API riusabile da piu' client (web, mobile)", "beneficio generale: modifiche localizzate, maggiore riusabilita' e manutenibilita'"] },
      { id:96, type:"mc", topic:"Status code 304", text:"Cosa indica una risposta HTTP con status code 304 (Not Modified)?", options:["Il browser aveva già una COPIA in CACHE della risorsa, e il server CONFERMA che la risorsa NON è CAMBIATA da allora; il browser può quindi USARE la versione in cache, evitando di RI-SCARICARE l'intero contenuto", "La richiesta ha avuto successo e contiene nuovi dati", "Il server ha rifiutato la richiesta per motivi di autorizzazione", "304 indica sempre un errore grave del server"], correct:0, explanation:"Il browser, avendo in cache una risorsa con un certo 'ETag' o 'Last-Modified', può inviare header come 'If-None-Match'/'If-Modified-Since' per chiedere al server 'questa risorsa è cambiata da quando l'ho scaricata?'; se il server determina che NON è cambiata, risponde con 304 (SENZA il body della risorsa, risparmiando banda) - il browser usa la VERSIONE IN CACHE; se invece è cambiata, risponde normalmente con 200 e il nuovo contenuto." },
      { id:97, type:"mc", topic:"Validazione email", text:"Perché, anche con una regex di validazione email perfetta lato client/server, è comunque consigliabile (in molti sistemi) INVIARE UNA EMAIL DI CONFERMA all'indirizzo fornito durante la registrazione?", options:["Una regex può verificare solo che la STRINGA abbia un FORMATO sintatticamente plausibile (es. contiene '@' e un dominio), ma NON può verificare che l'indirizzo EFFETTIVAMENTE ESISTA e APPARTENGA alla persona che si sta registrando; l'email di conferma verifica il POSSESSO REALE della casella di posta", "Le regex non possono essere usate per validare le email, solo PHP può farlo", "L'email di conferma serve solo per scopi di marketing", "Inviare un'email di conferma è richiesto dalla sintassi HTML5"], correct:0, explanation:"Una stringa come 'utente@dominio-inesistente-12345.com' potrebbe PASSARE una validazione di FORMATO (sembra un'email sintatticamente valida), ma il DOMINIO potrebbe non esistere, o l'indirizzo potrebbe appartenere a QUALCUN ALTRO (un utente potrebbe registrarsi con l'email di un'altra persona per errore o malizia); inviando un'email con un LINK DI CONFERMA univoco (contenente un token segreto), e attivando l'account SOLO dopo che l'utente clicca quel link, si verifica che: (1) l'indirizzo esiste REALMENTE, (2) chi si sta registrando ha ACCESSO a quella casella - una verifica che NESSUNA regex potrebbe fornire." },
      { id:98, type:"mc", topic:"Differenza require/import", text:"In un progetto JavaScript moderno (Node.js o frontend con bundler), qual è una differenza tra 'require()' (CommonJS) e 'import' (ES Modules)?", options:["require() è SINCRONO e valutato a RUNTIME (può essere condizionale, dentro un if); import è generalmente STATICO (le dichiarazioni sono 'issate' all'inizio del modulo, analizzabili a TEMPO DI COMPILAZIONE/BUILD, permettendo ottimizzazioni come il 'tree-shaking')", "Sono sintatticamente e funzionalmente identici in ogni contesto", "require() funziona solo nel browser, import solo in Node.js", "import non può importare funzioni, solo classi"], correct:0, explanation:"CommonJS ('const modulo = require(\"./modulo\")') è il sistema di moduli tradizionale di Node.js: le 'require' vengono valutate quando il codice le INCONTRA durante l'esecuzione (possono essere condizionali). ES Modules ('import { funzione } from \"./modulo.js\"') è lo standard JavaScript moderno: le dichiarazioni import/export sono STATICHE (devono essere al livello superiore del modulo, non condizionali), il che permette ai BUNDLER (Webpack, Rollup, Vite) di ANALIZZARE staticamente le dipendenze e applicare 'tree-shaking' (escludere dal bundle finale codice/export non utilizzati), riducendo la dimensione del bundle." },
      { id:99, type:"open", topic:"Riepilogo accessibilità", text:"Spiega cosa significa 'accessibilità web' (web accessibility, spesso abbreviato a11y) e fornisci 3 esempi concreti di tecniche/attributi HTML che migliorano l'accessibilità di un'applicazione web.", modelAnswer:"L'ACCESSIBILITÀ WEB significa progettare siti/applicazioni FRUIBILI da TUTTI gli utenti, INCLUSE persone con DISABILITÀ (visive, motorie, cognitive, uditive) che spesso utilizzano TECNOLOGIE ASSISTIVE come SCREEN READER (che 'leggono' la pagina ad alta voce), navigazione SOLO DA TASTIERA (senza mouse), o browser con FONT INGRANDITI/contrasti elevati. ESEMPI CONCRETI: (1) ATTRIBUTO 'alt' sulle immagini ('<img src=\"logo.png\" alt=\"Logo dell'azienda XYZ\">'): uno screen reader LEGGE il testo alternativo per descrivere l'immagine a un utente non vedente; se 'alt' è VUOTO o MANCANTE, l'utente non riceve alcuna informazione sul contenuto dell'immagine (un'immagine puramente decorativa dovrebbe avere 'alt=\"\"' per essere ESPLICITAMENTE ignorata dallo screen reader). (2) ETICHETTE <label> ASSOCIATE ai campi dei form ('<label for=\"email\">Email:</label><input id=\"email\" type=\"email\">'): permette a uno screen reader di ANNUNCIARE 'Email' quando l'utente naviga sul campo input, e permette di CLICCARE sul testo dell'etichetta per FOCALIZZARE il campo (utile anche per utenti con difficoltà motorie che hanno target di click più grandi). (3) NAVIGAZIONE DA TASTIERA e ORDINE LOGICO del 'tabindex': un'applicazione deve essere COMPLETAMENTE utilizzabile premendo TAB (per spostarsi tra elementi interattivi) e ENTER/SPAZIO (per attivarli), SENZA richiedere il mouse; elementi interattivi creati con <div onclick=...> invece di <button> sono PROBLEMATICI poiché un <div> non riceve automaticamente il focus da tastiera, a differenza di <button> o <a>. Altri esempi: attributi ARIA (aria-label, role) per componenti complessi, contrasto colore sufficiente tra testo e sfondo, dimensioni del testo ridimensionabili.", keywords:["accessibilita': progettare per utenti con disabilita' che usano tecnologie assistive come screen reader o navigazione da tastiera", "attributo alt sulle immagini per descrivere il contenuto agli screen reader", "label associate ai campi form (for/id) per annuncio screen reader e click sull'etichetta", "navigazione completa da tastiera (tab/enter), uso di elementi semantici come button invece di div con onclick"] },
      { id:100, type:"mc", topic:"Riepilogo finale", text:"Quale affermazione descrive meglio il rapporto tra HTML, CSS, JavaScript, PHP e MySQL in un'applicazione web dinamica completa?", options:["HTML/CSS/JavaScript costituiscono il FRONTEND (eseguito nel BROWSER dell'utente, occupandosi di struttura, stile e interattività); PHP costituisce il BACKEND (eseguito sul SERVER, gestendo logica di business, autenticazione, comunicazione con il database); MySQL è il DATABASE (memorizza i dati persistenti in modo strutturato, interrogato dal backend tramite query SQL)", "Tutti questi linguaggi/tecnologie sono completamente intercambiabili tra loro", "MySQL è un linguaggio di programmazione come PHP, eseguito nel browser", "JavaScript e PHP fanno esattamente la stessa cosa, sono ridondanti"], correct:0, explanation:"Un'applicazione web dinamica tipica ha una architettura a STRATI: il FRONTEND (HTML per la struttura, CSS per la presentazione, JavaScript per il comportamento/interattività) viene eseguito nel BROWSER dell'utente; il BACKEND (es. PHP) viene eseguito sul SERVER, riceve le richieste HTTP, esegue la LOGICA DI BUSINESS (validazione, calcoli, autenticazione/autorizzazione), e comunica con il DATABASE (MySQL) per LEGGERE/SCRIVERE dati PERSISTENTI tramite query SQL, restituendo poi una risposta (HTML generato dinamicamente, o JSON per chiamate AJAX/API) al frontend. Ogni STRATO ha una RESPONSABILITÀ specifica e comunica con gli altri tramite interfacce ben definite (HTTP per frontend-backend, SQL/driver per backend-database)." },
    ],
  };

  Object.keys(extra8).forEach((topic) => {
    if (!window.QUIZ_DATA[topic]) window.QUIZ_DATA[topic] = [];
    window.QUIZ_DATA[topic] = window.QUIZ_DATA[topic].concat(extra8[topic]);
  });
})();
